data class CallAgeRangeInput(
    val min: Int,
    val max: Int,
)

// Payload DTO (Mutation 반환용)
data class UpdateProfilePayload(
    val profile: UserProfileResponse,
)

// 프로필 응답 DTO
data class UserProfileResponse(
    val userId: String,
    val nickname: String,
    val bio: String?,
    val gender: String,
    val birthYear: Int,
    val regionCode: String?,
    val profileImageUrl: String?,
    val introVoiceUrl: String?,
    val interestTags: List<InterestTagResponse>,
    val callGenderPreference: String,
    val callAgeRangeMin: Int?,
    val callAgeRangeMax: Int?,
    val mannerScore: Double,
    val createdAt: String,
    val updatedAt: String,
)

data class InterestTagResponse(
    val id: String,
    val name: String,
    val category: String,
)

// Proto -> Response 변환 확장 함수
fun ProfileProto.toResponse(): UserProfileResponse = UserProfileResponse(
    userId = this.userId,
    nickname = this.nickname,
    bio = this.bio.takeIf { it.isNotBlank() },
    gender = this.gender.name,
    birthYear = this.birthYear,
    regionCode = this.regionCode.takeIf { it.isNotBlank() },
    profileImageUrl = this.profileImageUrl.takeIf { it.isNotBlank() },
    introVoiceUrl = this.introVoiceUrl.takeIf { it.isNotBlank() },
    interestTags = this.interestTagsList.map { it.toResponse() },
    callGenderPreference = this.callGenderPreference.name,
    callAgeRangeMin = this.callAgeRangeMin.takeIf { it > 0 },
    callAgeRangeMax = this.callAgeRangeMax.takeIf { it > 0 },
    mannerScore = this.mannerScore,
    createdAt = this.createdAt,
    updatedAt = this.updatedAt,
)
