## 7. gRPC Proto 정의 (참고)

**파일 위치:** `protobuf/src/main/proto/profile/profile_service.proto`

```protobuf
syntax = "proto3";
package profile;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.profile";

service ProfileService {
  rpc GetProfile(GetProfileRequest) returns (GetProfileResponse);
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
}

message GetProfileRequest {
  string user_id = 1;
}

message GetProfileResponse {
  Profile profile = 1;
}

message UpdateProfileRequest {
  string user_id = 1;
  optional string nickname = 2;
  optional string bio = 3;
  optional string region_code = 4;
  optional string profile_image_url = 5;
  optional string intro_voice_url = 6;
  repeated string interest_tag_ids = 7;
  optional GenderPreference call_gender_preference = 8;
  optional int32 call_age_range_min = 9;
  optional int32 call_age_range_max = 10;
}

message UpdateProfileResponse {
  Profile profile = 1;
}

message Profile {
  string user_id = 1;
  string nickname = 2;
  string bio = 3;
  string gender = 4;
  int32 birth_year = 5;
  string region_code = 6;
  string profile_image_url = 7;
  string intro_voice_url = 8;
  repeated InterestTag interest_tags = 9;
  GenderPreference call_gender_preference = 10;
  int32 call_age_range_min = 11;
  int32 call_age_range_max = 12;
  double manner_score = 13;
  string created_at = 14;
  string updated_at = 15;
}

message InterestTag {
  string id = 1;
  string name = 2;
  string category = 3;
}

enum GenderPreference {
  ANY = 0;
  MALE = 1;
  FEMALE = 2;
}
```

